    int low_mid = Math.floorDiv(digit_list.length - 1, 2);
    while (high_mid < digit_list.length && low_mid >= 0) {
        if (digit_list[high_mid] == 9) {
            digit_list[high_mid] = 0;
            digit_list[low_mid] = 0;
            high_mid += 1;
            low_mid -= 1;
